import asyncio
import anyio

class Proxy:
    def __init__(self, timeout: float = 2.0):
        self.timeout = timeout

    async def forward(self, url: str):
        try:
            # BUG: using asyncio.timeout inside an anyio CancelScope that shields
            # the inner task — the outer deadline fires but cancellation gets stuck
            # until the scope exits.
            async with anyio.CancelScope(shield=True):
                async with asyncio.timeout(self.timeout):
                    return await self._call_upstream(url)
        except TimeoutError as e:
            raise TimeoutError(
                f"upstream {url!r} exceeded {self.timeout:.1f}s budget "
                f"(outer scope shielded inner cancel)"
            ) from e

    async def _call_upstream(self, url):
        await asyncio.sleep(10)  # simulate hang
        return {"ok": True}

if __name__ == '__main__':
    asyncio.run(Proxy(timeout=2.0).forward("https://api.example.com/v1/score"))
